import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import copy from "copy-to-clipboard";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function EmployeeManagement() {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    id: null,
    rolePermissionId: "",
    prefix: "Mr",
    name: "",
    email: "",
    phone: "",
    status: "",
    totalBalance: "",
    commissionPercentage: "",
    commissionAmount: "",
    orgName: "",
  });

  const [filters, setFilters] = useState({
    employeeSearch: "",
    status: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const employeesPerPage = 10;

  const modalRef = useRef(null);
  const navigate = useNavigate();

  /* ================= FETCH EMPLOYEES ================= */
  function fetchEmployees() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/employees", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((response) => {
        if (response.data.success) {
          setEmployees(response.data.data);
        } else {
          toast.error("Failed to fetch employees");
        }
      })
      .catch((err) => {
        toast.error(err.response?.data?.error || "Error fetching employees");
      })
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchEmployees();
  }, [navigate]);

  /* ================= INPUT CHANGE ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  }

  /* ================= FILTER CHANGE ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1);
  }

  /* ================= EDIT ================= */
  function handleEdit(emp) {
    setFormData({
      id: emp.id,
      rolePermissionId: emp.rolePermissionId,
      prefix: emp.prefix,
      name: emp.name,
      email: emp.email,
      phone: emp.phone,
      status: emp.status,
      totalBalance: emp.totalBalance,
      commissionPercentage: emp.commissionPercentage,
      commissionAmount: emp.commissionAmount,
      orgName: emp.orgName,
    });

    const modalElement = document.getElementById("editEmployeeModal");
    modalRef.current = new Modal(modalElement);
    modalRef.current.show();
  }

  /* ================= UPDATE ================= */
  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    axios
      .put(API_BASE_URL + "/employees/" + formData.id, formData, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Employee updated successfully");
        fetchEmployees();
        modalRef.current.hide();
      })
      .catch((err) => {
        toast.error(err.response?.data?.error || "Update failed");
      });
  }

  /* ================= FILTERED EMPLOYEES ================= */
  const filteredEmployees = employees.filter((emp) => {
    const employeeSearchMatch = filters.employeeSearch
      ? (emp.name + emp.phone + emp.email + emp.role)
          .toLowerCase()
          .includes(filters.employeeSearch.toLowerCase())
      : true;

    return (
      employeeSearchMatch &&
      (filters.status ? emp.status === filters.status : true)
    );
  });

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * employeesPerPage;
  const indexOfFirst = indexOfLast - employeesPerPage;
  const currentEmployees = filteredEmployees.slice(
    indexOfFirst,
    indexOfLast
  );
  const totalPages = Math.ceil(filteredEmployees.length / employeesPerPage);

  function goToNextPage() {
    if (currentPage < totalPages) setCurrentPage((prev) => prev + 1);
  }

  function goToPreviousPage() {
    if (currentPage > 1) setCurrentPage((prev) => prev - 1);
  }

  /* ================= COPY ================= */
  function handleCopy(text, type) {
    if (copy(text)) toast.success(type + " copied to clipboard");
  }

  /* ================= DETAILS MODAL ================= */
  const [detailsEmployee, setDetailsEmployee] = useState(null);
  const detailsModalRef = useRef(null);

  function openDetailsModal(emp) {
    setDetailsEmployee(emp);
    const modalEl = document.getElementById("detailsModal");
    detailsModalRef.current = new Modal(modalEl);
    detailsModalRef.current.show();
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate("/dashboard")}
          ></i>
        </div>
      </div>

      <div className="row mb-3">
        <div className="col">
          <h4 className="fw-bold mb-0">Employee Management</h4>
        </div>
      </div>

      {/* ================= FILTERS ================= */}
      <div className="row g-3 mb-3">
        <div className="col-md-6">
          <input
            type="text"
            name="employeeSearch"
            className="form-control form-control-sm"
            placeholder="Search Employee (Name, Phone, Email, Role)"
            value={filters.employeeSearch}
            onChange={handleFilterChange}
          />
        </div>

        <div className="col-md-6">
          <select
            name="status"
            className="form-select form-select-sm"
            value={filters.status}
            onChange={handleFilterChange}
          >
            <option value="">Status</option>
            <option value="Active">Active</option>
            <option value="Inactive">Inactive</option>
          </select>
        </div>
      </div>

      {/* ================= TABLE ================= */}
      <div className="card mb-3">
        <div className="card border-0">
          {loading ? (
            <div className="text-center">Loading...</div>
          ) : (
            <div className="table-responsive rounded">
              <table className="table table-striped table-hover mb-0 small">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Name</th>
                    <th>Contact</th>
                    <th>Role</th>
                    <th>Status</th>
                    <th>Balance</th>
                    <th>Date & Time</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {currentEmployees.map((emp) => (
                    <tr key={emp.id}>
                      <td>{emp.id}</td>
                      <td>{emp.prefix} {emp.name}</td>
                      <td>
                        <i
                          className="fa-solid fa-phone text-success me-2"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleCopy(emp.phone, "Phone")}
                        ></i>
                        <i
                          className="fa-solid fa-envelope text-primary me-2"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleCopy(emp.email, "Email")}
                        ></i>
                        <i
                          className="fa-solid fa-id-card text-secondary"
                          style={{ cursor: "pointer" }}
                          onClick={() => openDetailsModal(emp)}
                        ></i>
                      </td>
                      <td>{emp.role}</td>
                      <td>{emp.status}</td>
                      <td>{emp.totalBalance}</td>
                      <td>
                        <small>
                          Created: {new Date(emp.createdAt).toLocaleString()}
                        </small>
                        <br />
                        <small>
                          Updated: {new Date(emp.updatedAt).toLocaleString()}
                        </small>
                      </td>
                      <td>
                        <i
                          className="fa-solid fa-pen-to-square text-primary"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleEdit(emp)}
                        ></i>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {/* ================= PAGINATION ================= */}
      <div className="d-flex justify-content-between align-items-center mb-3">
        <div>
          Page {currentPage} of {totalPages} • {filteredEmployees.length} records
        </div>
        <div>
          <button
            className="btn btn-sm border-0"
            onClick={goToPreviousPage}
            disabled={currentPage === 1}
          >
            ◀
          </button>
          <button
            className="btn btn-sm border-0"
            onClick={goToNextPage}
            disabled={currentPage === totalPages || totalPages === 0}
          >
            ▶
          </button>
        </div>
      </div>

      {/* ================= EDIT MODAL ================= */}
      <div className="modal fade" id="editEmployeeModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5 className="modal-title">Edit Employee</h5>
                <button type="button" className="btn-close" data-bs-dismiss="modal"></button>
              </div>

              <div className="modal-body">
                <div className="mb-3">
                  <label>Full Name</label>
                  <input
                    type="text"
                    name="name"
                    className="form-control"
                    value={formData.name}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Email</label>
                  <input
                    type="email"
                    name="email"
                    className="form-control"
                    value={formData.email}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Phone</label>
                  <input
                    type="text"
                    name="phone"
                    className="form-control"
                    value={formData.phone}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Status</label>
                  <select
                    name="status"
                    className="form-select"
                    value={formData.status}
                    onChange={handleInputChange}
                  >
                    <option value="Active">Active</option>
                    <option value="Inactive">Inactive</option>
                  </select>
                </div>
              </div>

              <div className="modal-footer">
                <button type="submit" className="btn btn-primary">
                  Update
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>

      {/* ================= DETAILS MODAL ================= */}
      <div className="modal fade" id="detailsModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <div className="modal-header">
              <h5 className="modal-title">Employee Details</h5>
              <button type="button" className="btn-close" data-bs-dismiss="modal"></button>
            </div>

            <div className="modal-body">
              {detailsEmployee && (
                <>
                  <p><strong>Role:</strong> {detailsEmployee.role}</p>
                  <p><strong>Commission %:</strong> {detailsEmployee.commissionPercentage}</p>
                  <p><strong>Commission Amount:</strong> {detailsEmployee.commissionAmount}</p>
                  <p><strong>Organization:</strong> {detailsEmployee.orgName}</p>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

    </div>
  );
}

export default EmployeeManagement;
